class Instrument():

    @staticmethod
    def control(check_errors=False):
        pass

class Instr(Instrument):

    @staticmethod
    def checked_control(*args, **kwargs):
        kwargs.setdefault('check_errors', True)
        return Instrument.control(*args, **kwargs)

    prop = checked_control.__func__()
