In the manifest loader, each entry's chunk paths [are split into `.js` and `.css`](https://github.com/inveniosoftware/pywebpack/blob/b78bc745cd0d9c081da1b7356d254d0089746ed9/pywebpack/manifests.py#L193-L205), so usage remains the same. What changes is that there is no need to actually include the runtime and vendor chunks explicitly, they are automatically picked up as dependencies of each entry:

```diff
- {{ webpack['manifest'] }}
- {{ webpack['vendor'] }}
{# This will include the above #}
{{ webpack['base'] }}
```

Fwiw my impl was this:
```rust
#[derive(Debug)]
struct FileBuf {
  digest: Digest,
  file: tokio::fs::File,
  buf: BytesMut,
  chunk_size_bytes: usize,
  offset: usize,
}

impl FileBuf {
  fn new(digest: Digest, file: tokio::fs::File, chunk_size_bytes: usize) -> Self {
    Self {
      digest,
      file,
      buf: BytesMut::with_capacity(chunk_size_bytes),
      chunk_size_bytes,
      offset: 0,
    }
  }

  async fn advance(&mut self) -> Result<Option<Bytes>, std::io::Error> {
    if self.offset == self.digest.size_bytes {
      return Ok(None);
    }
    if self.buf.len() == self.chunk_size_bytes {
      return Ok(Some(self.buf.split().freeze()));
    }
    loop {
      let _read_bytes_len = self.file.read_buf(&mut self.buf).await?;
      if self.offset + self.buf.len() == self.digest.size_bytes
        || self.buf.len() >= self.chunk_size_bytes
      {
        self.offset += self.buf.len();
        let next_chunk = self.buf.split_off(self.chunk_size_bytes);
        let data = self.buf.clone().freeze();
        self.buf = next_chunk;
        return Ok(Some(data));
      }
    }
  }
}

pub async fn store_file<P: AsRef<Path>>(&self, digest: &Digest, path: P) -> Result<(), String> {
    let store_op = self.prepare_store_op(digest.to_owned());
    let resource_name = store_op.resource_name.clone();

    let len = digest.size_bytes;

    let file = tokio::fs::File::open(path)
      .map_err(|e| format!("{}", e))
      .await?;
    let mut file_buf = FileBuf::new(digest.to_owned(), file, self.chunk_size_bytes);
    let stream = async_stream::stream! {
        while let Some(data) = file_buf.advance().await.expect("TODO(John Sirois): XXX") {
            yield bazel_protos::gen::google::bytestream::WriteRequest {
              resource_name: resource_name.clone(),
              write_offset: (file_buf.offset - data.len()) as i64,
              finish_write: file_buf.offset == len,
              // TODO(tonic): Explore using the unreleased `Bytes` support in Prost from:
              // https://github.com/danburkert/prost/pull/341
              data
            };
        }
    };

    self.store_streaming(store_op, stream).await
  }
```

